import { useEffect, useState } from "react";
import API from "../services/api";

function Standings() {
  const [standings, setStandings] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    const fetchStandings = async () => {
      try {
        setLoading(true);
        const res = await API.get("/matches/standings");
        setStandings(res.data);
      } catch (err) {
        console.error("Error fetching standings:", err);
        setError(err.response?.data?.message || err.message);
      } finally {
        setLoading(false);
      }
    };

    fetchStandings();
  }, []);

  if (loading) return <div className="page"><p>Loading standings...</p></div>;
  if (error) return <div className="page"><p style={{ color: "red" }}>Error: {error}</p></div>;

  return (
    <div className="page">
      <h2>Points Table</h2>
      <div className="table-container" style={{ overflowX: 'auto' }}>
        <table style={{ width: '100%', borderCollapse: 'collapse', marginTop: '20px' }}>
          <thead>
            <tr style={{ backgroundColor: '#f4f4f4', textAlign: 'left' }}>
              <th style={{ padding: '12px', borderBottom: '2px solid #ddd' }}>Team</th>
              <th style={{ padding: '12px', borderBottom: '2px solid #ddd' }}>P</th>
              <th style={{ padding: '12px', borderBottom: '2px solid #ddd' }}>W</th>
              <th style={{ padding: '12px', borderBottom: '2px solid #ddd' }}>L</th>
              <th style={{ padding: '12px', borderBottom: '2px solid #ddd' }}>T</th>
              <th style={{ padding: '12px', borderBottom: '2px solid #ddd' }}>Pts</th>
            </tr>
          </thead>
          <tbody>
            {standings.map((row, index) => (
              <tr key={index} style={{ borderBottom: '1px solid #eee' }}>
                <td style={{ padding: '12px', fontWeight: 'bold' }}>{row.team}</td>
                <td style={{ padding: '12px' }}>{row.played}</td>
                <td style={{ padding: '12px' }}>{row.won}</td>
                <td style={{ padding: '12px' }}>{row.lost}</td>
                <td style={{ padding: '12px' }}>{row.tied}</td>
                <td style={{ padding: '12px', fontWeight: 'bold' }}>{row.points}</td>
              </tr>
            ))}
            {standings.length === 0 && (
              <tr>
                <td colSpan="6" style={{ padding: '20px', textAlign: 'center', color: '#999' }}>
                  No match data available to calculate standings.
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
}

export default Standings;
